import React, { useState, useEffect } from 'react';
import { submitAssessment, getAssessmentHistory } from '../api';

const ASSESSMENTS = {
  phq9: {
    name: 'PHQ-9 Depression Screening',
    desc: 'Over the last 2 weeks, how often have you been bothered by any of the following problems?',
    icon: '🧠',
    options: ['Not at all (0)', 'Several days (1)', 'More than half the days (2)', 'Nearly every day (3)'],
    questions: [
      'Little interest or pleasure in doing things',
      'Feeling down, depressed, or hopeless',
      'Trouble falling or staying asleep, or sleeping too much',
      'Feeling tired or having little energy',
      'Poor appetite or overeating',
      'Feeling bad about yourself — or that you are a failure',
      'Trouble concentrating on things, such as reading or watching TV',
      'Moving or speaking so slowly that other people could have noticed',
      'Thoughts that you would be better off dead or of hurting yourself',
    ],
  },
  gad7: {
    name: 'GAD-7 Anxiety Screening',
    desc: 'Over the last 2 weeks, how often have you been bothered by the following?',
    icon: '💭',
    options: ['Not at all (0)', 'Several days (1)', 'More than half the days (2)', 'Nearly every day (3)'],
    questions: [
      'Feeling nervous, anxious, or on edge',
      'Not being able to stop or control worrying',
      'Worrying too much about different things',
      'Trouble relaxing',
      'Being so restless that it is hard to sit still',
      'Becoming easily annoyed or irritable',
      'Feeling afraid, as if something awful might happen',
    ],
  },
  stress: {
    name: 'Perceived Stress Scale',
    desc: 'In the last month, how often have you felt or thought the following?',
    icon: '⚡',
    options: ['Never (0)', 'Almost never (1)', 'Sometimes (2)', 'Fairly often (3)'],
    questions: [
      'Upset because of something that happened unexpectedly',
      'Unable to control important things in your life',
      'Nervous and stressed',
      'Unable to cope with all the things you had to do',
      'Things in your life going your way (reverse scored)',
      'Difficulties were piling up so high you could not overcome them',
      'Irritable due to circumstances outside of your control',
    ],
  },
};

export default function Assessment() {
  const [selected, setSelected] = useState(null);
  const [answers, setAnswers] = useState([]);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState([]);

  useEffect(() => {
    getAssessmentHistory().then(r => setHistory(r.data || [])).catch(() => {});
  }, []);

  const start = (type) => {
    setSelected(type);
    setAnswers(new Array(ASSESSMENTS[type].questions.length).fill(null));
    setResult(null);
  };

  const answer = (qi, val) => {
    setAnswers(prev => { const n = [...prev]; n[qi] = val; return n; });
  };

  const submit = async () => {
    if (answers.some(a => a === null)) return alert('Please answer all questions.');
    setLoading(true);
    try {
      const res = await submitAssessment({ assessment_type: selected, responses: answers });
      setResult(res.data);
      getAssessmentHistory().then(r => setHistory(r.data || [])).catch(() => {});
    } catch {} finally { setLoading(false); }
  };

  const reset = () => { setSelected(null); setResult(null); setAnswers([]); };

  const asmtData = selected ? ASSESSMENTS[selected] : null;
  const answered = answers.filter(a => a !== null).length;
  const total = asmtData?.questions.length || 0;

  return (
    <div style={styles.page}>
      <h1 style={styles.title}>Self-Assessment</h1>
      <p style={styles.subtitle}>Standardized mental health screenings to understand your current wellbeing.</p>

      {/* Pick assessment */}
      {!selected && !result && (
        <>
          <div style={styles.typeGrid}>
            {Object.entries(ASSESSMENTS).map(([key, a]) => (
              <div key={key} className="card" style={styles.typeCard} onClick={() => start(key)}>
                <div style={styles.typeIcon}>{a.icon}</div>
                <div style={styles.typeName}>{a.name}</div>
                <div style={styles.typeDesc}>{a.questions.length} questions · ~3 mins</div>
                <button className="btn-primary" style={{ marginTop: 'auto', width: '100%', fontSize: '0.85rem', padding: '9px' }}>Start →</button>
              </div>
            ))}
          </div>

          {history.length > 0 && (
            <div className="card" style={{ marginTop: 24 }}>
              <h2 style={{ fontSize: '1.1rem', marginBottom: 16 }}>Assessment History</h2>
              <div style={styles.historyTable}>
                {history.map(h => (
                  <div key={h.id} style={styles.histRow}>
                    <span style={styles.histType}>{ASSESSMENTS[h.assessment_type]?.icon} {ASSESSMENTS[h.assessment_type]?.name || h.assessment_type}</span>
                    <span style={styles.histDate}>{new Date(h.taken_at).toLocaleDateString()}</span>
                    <span style={styles.histScore}>Score: {h.score}</span>
                    <span className={`badge badge-${h.risk_level}`}>{h.risk_level} risk</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {/* Quiz */}
      {selected && !result && asmtData && (
        <div style={styles.quizWrap}>
          <div style={styles.quizHeader}>
            <button className="btn-ghost" style={{ fontSize: '0.85rem', padding: '8px 16px' }} onClick={reset}>← Back</button>
            <div style={{ flex: 1 }}>
              <div style={styles.quizTitle}>{asmtData.icon} {asmtData.name}</div>
              <div style={styles.quizDesc}>{asmtData.desc}</div>
            </div>
          </div>

          {/* Progress */}
          <div style={styles.progressBar}>
            <div style={{ ...styles.progressFill, width: `${(answered / total) * 100}%` }} />
          </div>
          <div style={styles.progressLabel}>{answered}/{total} answered</div>

          <div style={styles.questions}>
            {asmtData.questions.map((q, i) => (
              <div key={i} className="card" style={{ ...styles.qCard, ...(answers[i] !== null ? styles.qCardDone : {}) }}>
                <div style={styles.qText}><span style={styles.qNum}>{i + 1}.</span> {q}</div>
                <div style={styles.options}>
                  {asmtData.options.map((opt, vi) => (
                    <label key={vi} style={{ ...styles.optLabel, ...(answers[i] === vi ? styles.optSelected : {}) }}>
                      <input type="radio" name={`q${i}`} value={vi} checked={answers[i] === vi}
                        onChange={() => answer(i, vi)} style={{ display: 'none' }} />
                      {opt}
                    </label>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <button className="btn-primary" style={{ marginTop: 24, padding: '14px 40px', fontSize: '1rem' }}
            onClick={submit} disabled={loading || answered < total}>
            {loading ? 'Analysing…' : answered < total ? `Answer all ${total} questions` : 'See My Results →'}
          </button>
        </div>
      )}

      {/* Result */}
      {result && (
        <div style={styles.resultWrap}>
          <div className="card" style={styles.resultCard}>
            <div style={styles.resultIcon}>{result.risk_level === 'low' ? '🟢' : result.risk_level === 'moderate' ? '🟡' : '🔴'}</div>
            <h2 style={styles.resultTitle}>{result.message}</h2>
            <div style={styles.resultMeta}>
              <span className={`badge badge-${result.risk_level}`} style={{ fontSize: '0.95rem', padding: '6px 18px' }}>{result.risk_level.toUpperCase()} RISK</span>
              <span style={{ color: 'var(--mist)', fontSize: '0.9rem' }}>Score: {result.score}</span>
            </div>
            <div style={styles.recSection}>
              <h3 style={styles.recTitle}>Recommendations</h3>
              {result.recommendations.map((r, i) => (
                <div key={i} style={styles.recItem}>
                  <span style={styles.recBullet}>→</span> {r}
                </div>
              ))}
            </div>
            {result.risk_level === 'high' && (
              <div style={styles.crisisAlert}>
                🆘 Please reach out for professional support immediately. You don't have to go through this alone.
              </div>
            )}
            <div style={styles.resultActions}>
              <button className="btn-primary" onClick={reset}>Take Another Assessment</button>
              <button className="btn-ghost" onClick={reset}>Back to All Assessments</button>
            </div>
          </div>
        </div>
      )}

      {/* Disclaimer */}
      <div style={styles.disclaimer}>
        ⚠️ These assessments are screening tools only and do not constitute a clinical diagnosis. Always consult a licensed mental health professional for proper evaluation and treatment.
      </div>
    </div>
  );
}

