  typeCard: { display: 'flex', flexDirection: 'column', gap: 8, cursor: 'pointer', transition: 'transform 0.2s' },
  typeIcon: { fontSize: 36 },
  typeName: { fontWeight: 700, fontSize: '1rem', color: 'var(--ink)' },
  typeDesc: { fontSize: '0.82rem', color: 'var(--mist)', marginBottom: 8 },
  historyTable: { display: 'flex', flexDirection: 'column', gap: 2 },
  histRow: { display: 'flex', alignItems: 'center', gap: 16, padding: '10px 0', borderBottom: '1px solid var(--border)', flexWrap: 'wrap' },
  histType: { flex: 1, fontWeight: 500, fontSize: '0.9rem' },
  histDate: { color: 'var(--mist)', fontSize: '0.82rem' },
  histScore: { fontWeight: 600, fontSize: '0.88rem', color: 'var(--ink)' },
  quizWrap: {},
