  quizDesc: { fontSize: '0.88rem', color: 'var(--mist)' },
  progressBar: { height: 6, background: 'var(--border)', borderRadius: 99, marginBottom: 6, overflow: 'hidden' },
  progressFill: { height: '100%', background: 'linear-gradient(90deg, var(--teal), var(--sage))', borderRadius: 99, transition: 'width 0.3s' },
  progressLabel: { fontSize: '0.8rem', color: 'var(--mist)', marginBottom: 20 },
  questions: { display: 'flex', flexDirection: 'column', gap: 16 },
  qCard: { transition: 'border-color 0.2s' },
