  },
  optSelected: { background: 'var(--sage-pale)', borderColor: 'var(--sage)', color: 'var(--teal-dark)', fontWeight: 600 },
  resultWrap: { display: 'flex', justifyContent: 'center' },
  resultCard: { maxWidth: 560, width: '100%', textAlign: 'center', padding: 40 },
  resultIcon: { fontSize: 56, marginBottom: 16 },
  resultTitle: { fontSize: '1.5rem', marginBottom: 16 },
  resultMeta: { display: 'flex', gap: 16, justifyContent: 'center', alignItems: 'center', marginBottom: 28 },
  recSection: { textAlign: 'left', marginBottom: 24 },
  recTitle: { fontSize: '1rem', marginBottom: 12, color: 'var(--ink)' },
  recItem: { display: 'flex', gap: 8, marginBottom: 8, fontSize: '0.9rem', color: 'var(--ink-light)', alignItems: 'flex-start' },
  recBullet: { color: 'var(--teal)', fontWeight: 700, flexShrink: 0 },
  crisisAlert: { background: 'var(--rose-pale)', border: '1px solid var(--rose)', color: '#b03a4a', padding: '12px 16px', borderRadius: 'var(--radius-sm)', marginBottom: 20, fontSize: '0.9rem' },
  resultActions: { display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' },
  disclaimer: { marginTop: 32, padding: '14px 20px', background: 'var(--amber-pale)', border: '1px solid #f0d0a0', borderRadius: 'var(--radius-sm)', fontSize: '0.83rem', color: 'var(--ink-light)', lineHeight: 1.5 },
};
